"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[1247],{89176(n,t,r){r.r(t),r.d(t,{assets:()=>i,contentTitle:()=>a,default:()=>d,frontMatter:()=>c,metadata:()=>e,toc:()=>l});const e=JSON.parse('{"id":"cpp20/consteval","title":"consteval \u7acb\u5373\u51fd\u6570","description":"C++20 consteval \u7acb\u5373\u51fd\u6570 \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/07-consteval.md","sourceDirName":"cpp20","slug":"/cpp20/07-consteval","permalink":"/LearnModernCpp/docs/cpp20/07-consteval","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"consteval","permalink":"/LearnModernCpp/docs/tags/consteval"}],"version":"current","sidebarPosition":8,"frontMatter":{"sidebar_position":8,"slug":"07-consteval","title":"consteval \u7acb\u5373\u51fd\u6570","description":"C++20 consteval \u7acb\u5373\u51fd\u6570 \u6559\u5b66\u793a\u4f8b","tags":["cpp20","consteval"]},"sidebar":"docs","previous":{"title":"\u6307\u5b9a\u521d\u59cb\u5316\u5668 (Designated Initializers)","permalink":"/LearnModernCpp/docs/cpp20/06-designated-initializers"},"next":{"title":"constinit","permalink":"/LearnModernCpp/docs/cpp20/08-constinit"}}');var s=r(74848),o=r(28453);const c={sidebar_position:8,slug:"07-consteval",title:"consteval \u7acb\u5373\u51fd\u6570",description:"C++20 consteval \u7acb\u5373\u51fd\u6570 \u6559\u5b66\u793a\u4f8b",tags:["cpp20","consteval"]},a="consteval \u7acb\u5373\u51fd\u6570",i={},l=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"consteval-\u7acb\u5373\u51fd\u6570",children:"consteval \u7acb\u5373\u51fd\u6570"})}),"\n",(0,s.jsx)(t.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 consteval \u7acb\u5373\u51fd\u6570 \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp20/07_consteval.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: consteval \u7acb\u5373\u51fd\u6570\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: consteval \u5173\u952e\u5b57\u58f0\u660e\u7684\u51fd\u6570\u662f"\u7acb\u5373\u51fd\u6570"\uff08immediate function\uff09\uff0c\r\n *          \u5fc5\u987b\u5728\u7f16\u8bd1\u671f\u6c42\u503c\uff0c\u4e0d\u80fd\u5728\u8fd0\u884c\u65f6\u8c03\u7528\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: constexpr \u51fd\u6570\u867d\u7136\u53ef\u4ee5\u5728\u7f16\u8bd1\u671f\u6c42\u503c\uff0c\r\n *             \u4f46\u4e0d\u4fdd\u8bc1\u4e00\u5b9a\u5728\u7f16\u8bd1\u671f\u6267\u884c\u3002consteval \u63d0\u4f9b\u4e86\u66f4\u5f3a\u7684\u4fdd\u8bc1\uff1a\r\n *             \u5982\u679c\u4e0d\u80fd\u5728\u7f16\u8bd1\u671f\u6c42\u503c\uff0c\u5219\u76f4\u63a5\u62a5\u7f16\u8bd1\u9519\u8bef\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - consteval \u51fd\u6570\u5fc5\u987b\u5728\u7f16\u8bd1\u671f\u6c42\u503c\r\n *   - \u5982\u679c\u4f20\u5165\u8fd0\u884c\u65f6\u53d8\u91cf\uff0c\u7f16\u8bd1\u9519\u8bef\r\n *   - \u53ef\u7528\u4e8e\u7f16\u8bd1\u671f\u65ad\u8a00\u3001\u7f16\u8bd1\u671f\u8ba1\u7b97\u3001\u7f16\u8bd1\u671f\u4ee3\u7801\u751f\u6210\r\n *   - \u4e0e constexpr \u7684\u5173\u952e\u533a\u522b\uff1aconstexpr \u662f"\u53ef\u4ee5"\uff0cconsteval \u662f"\u5fc5\u987b"\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <array>\r\n#include <cstdint>\r\n#include <type_traits>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// consteval \u51fd\u6570\uff1a\u5fc5\u987b\u5728\u7f16\u8bd1\u671f\u6c42\u503c\r\nconsteval int square(int n) {\r\n    return n * n;\r\n}\r\n\r\n// constexpr \u51fd\u6570\uff08\u5bf9\u6bd4\uff09\uff1a\u53ef\u4ee5\u7f16\u8bd1\u671f\uff0c\u4e5f\u53ef\u4ee5\u8fd0\u884c\u65f6\r\nconstexpr int cube(int n) {\r\n    return n * n * n;\r\n}\r\n\r\n// consteval \u9636\u4e58\r\nconsteval long long factorial(int n) {\r\n    long long result = 1;\r\n    for (int i = 2; i <= n; ++i) {\r\n        result *= i;\r\n    }\r\n    return result;\r\n}\r\n\r\n// consteval \u7f16\u8bd1\u671f\u5b57\u7b26\u4e32\u957f\u5ea6\r\nconsteval std::size_t compile_time_strlen(const char* str) {\r\n    std::size_t len = 0;\r\n    while (str[len] != \'\\0\') {\r\n        ++len;\r\n    }\r\n    return len;\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // consteval \u51fd\u6570\u5fc5\u987b\u7528\u7f16\u8bd1\u671f\u5e38\u91cf\u8c03\u7528\r\n    constexpr int result1 = square(5);  // \u7f16\u8bd1\u671f\u8ba1\u7b97\r\n    std::cout << "square(5) = " << result1 << "\\n";\r\n\r\n    // \u53ef\u4ee5\u76f4\u63a5\u7528\u5b57\u9762\u91cf\r\n    std::cout << "square(10) = " << square(10) << "\\n";\r\n\r\n    // \u5bf9\u6bd4 constexpr\r\n    constexpr int result2 = cube(3);  // \u7f16\u8bd1\u671f\u8ba1\u7b97\r\n    std::cout << "cube(3) = " << result2 << "\\n";\r\n\r\n    int runtime_val = 4;\r\n    int result3 = cube(runtime_val);  // \u8fd0\u884c\u65f6\u8ba1\u7b97 \u2014\u2014 constexpr \u5141\u8bb8!\r\n    std::cout << "cube(runtime_val=4) = " << result3 << "\\n";\r\n\r\n    // int bad = square(runtime_val);  // \u7f16\u8bd1\u9519\u8bef! consteval \u4e0d\u5141\u8bb8\u8fd0\u884c\u65f6\u53c2\u6570\r\n\r\n    // \u7f16\u8bd1\u671f\u9636\u4e58\r\n    std::cout << "\\n\u7f16\u8bd1\u671f\u9636\u4e58:\\n";\r\n    std::cout << "10! = " << factorial(10) << "\\n";\r\n    std::cout << "15! = " << factorial(15) << "\\n";\r\n    std::cout << "20! = " << factorial(20) << "\\n";\r\n\r\n    // \u7f16\u8bd1\u671f\u5b57\u7b26\u4e32\u957f\u5ea6\r\n    constexpr auto len = compile_time_strlen("Hello, C++20!");\r\n    std::cout << "\\n\\"Hello, C++20!\\" \u7684\u957f\u5ea6: " << len << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// \u7f16\u8bd1\u671f\u67e5\u627e\u8868\u751f\u6210\r\nconsteval auto generate_squares() {\r\n    std::array<int, 16> table{};\r\n    for (int i = 0; i < 16; ++i) {\r\n        table[static_cast<std::size_t>(i)] = i * i;\r\n    }\r\n    return table;\r\n}\r\n\r\n// \u7f16\u8bd1\u671f\u6590\u6ce2\u90a3\u5951\r\nconsteval auto generate_fibonacci() {\r\n    std::array<long long, 20> fib{};\r\n    fib[0] = 0;\r\n    fib[1] = 1;\r\n    for (int i = 2; i < 20; ++i) {\r\n        fib[static_cast<std::size_t>(i)] =\r\n            fib[static_cast<std::size_t>(i - 1)] +\r\n            fib[static_cast<std::size_t>(i - 2)];\r\n    }\r\n    return fib;\r\n}\r\n\r\n// consteval \u7528\u4e8e\u7f16\u8bd1\u671f\u9a8c\u8bc1\r\nconsteval int safe_divide(int a, int b) {\r\n    if (b == 0) {\r\n        // \u5982\u679c b \u662f 0\uff0c\u7f16\u8bd1\u671f\u5c31\u4f1a\u62a5\u9519\r\n        // \u56e0\u4e3a throw \u4e0d\u80fd\u5728\u5e38\u91cf\u6c42\u503c\u4e2d\u6267\u884c\r\n        throw "\u9664\u6570\u4e0d\u80fd\u4e3a\u96f6!";\r\n    }\r\n    return a / b;\r\n}\r\n\r\n// \u7f16\u8bd1\u671f\u4f4d\u64cd\u4f5c\r\nconsteval uint32_t make_color(uint8_t r, uint8_t g, uint8_t b, uint8_t a = 255) {\r\n    return (static_cast<uint32_t>(a) << 24) |\r\n           (static_cast<uint32_t>(r) << 16) |\r\n           (static_cast<uint32_t>(g) << 8)  |\r\n           static_cast<uint32_t>(b);\r\n}\r\n\r\n// \u4f7f\u7528 consteval \u505a\u7f16\u8bd1\u671f\u7c7b\u578b\u68c0\u67e5\u8f85\u52a9\r\nconsteval bool is_power_of_two(unsigned int n) {\r\n    return n > 0 && (n & (n - 1)) == 0;\r\n}\r\n\r\n// consteval \u5728\u6a21\u677f\u4e2d\u4f7f\u7528\r\ntemplate<int N>\r\nconsteval auto make_iota_array() {\r\n    std::array<int, N> arr{};\r\n    for (int i = 0; i < N; ++i) {\r\n        arr[static_cast<std::size_t>(i)] = i;\r\n    }\r\n    return arr;\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u7f16\u8bd1\u671f\u67e5\u627e\u8868\r\n    constexpr auto squares = generate_squares();\r\n    std::cout << "\u5e73\u65b9\u8868: ";\r\n    for (int i = 0; i < 10; ++i) {\r\n        std::cout << squares[static_cast<std::size_t>(i)] << " ";\r\n    }\r\n    std::cout << "...\\n";\r\n\r\n    // \u7f16\u8bd1\u671f\u6590\u6ce2\u90a3\u5951\r\n    constexpr auto fib = generate_fibonacci();\r\n    std::cout << "\u6590\u6ce2\u90a3\u5951: ";\r\n    for (int i = 0; i < 15; ++i) {\r\n        std::cout << fib[static_cast<std::size_t>(i)] << " ";\r\n    }\r\n    std::cout << "...\\n";\r\n\r\n    // \u7f16\u8bd1\u671f\u5b89\u5168\u9664\u6cd5\r\n    constexpr int div_result = safe_divide(100, 7);\r\n    std::cout << "\\n\u5b89\u5168\u9664\u6cd5 100/7 = " << div_result << "\\n";\r\n    // constexpr int bad = safe_divide(100, 0);  // \u7f16\u8bd1\u9519\u8bef! \u9664\u6570\u4e3a\u96f6\r\n\r\n    // \u7f16\u8bd1\u671f\u989c\u8272\u503c\r\n    constexpr auto red   = make_color(255, 0, 0);\r\n    constexpr auto green = make_color(0, 255, 0);\r\n    constexpr auto blue  = make_color(0, 0, 255);\r\n    std::cout << "\\n\u989c\u8272\u503c (ARGB):\\n";\r\n    std::cout << "  \u7ea2: 0x" << std::hex << red << "\\n";\r\n    std::cout << "  \u7eff: 0x" << green << "\\n";\r\n    std::cout << "  \u84dd: 0x" << blue << "\\n";\r\n    std::cout << std::dec;\r\n\r\n    // \u7f16\u8bd1\u671f\u4e8c\u7684\u5e42\u68c0\u6d4b\r\n    static_assert(is_power_of_two(256), "256 \u5e94\u8be5\u662f 2 \u7684\u5e42");\r\n    static_assert(!is_power_of_two(100), "100 \u4e0d\u662f 2 \u7684\u5e42");\r\n    std::cout << "\\n256 \u662f 2 \u7684\u5e42: " << std::boolalpha << is_power_of_two(256) << "\\n";\r\n    std::cout << "100 \u662f 2 \u7684\u5e42: " << is_power_of_two(100) << "\\n";\r\n\r\n    // \u7f16\u8bd1\u671f\u6570\u7ec4\u751f\u6210\r\n    constexpr auto iota5 = make_iota_array<5>();\r\n    std::cout << "\\niota<5>: ";\r\n    for (auto v : iota5) std::cout << v << " ";\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1a\u4e0d\u80fd\u4f20\u5165\u8fd0\u884c\u65f6\u53d8\u91cf\r\n    std::cout << "1. consteval \u51fd\u6570\u4e0d\u80fd\u63a5\u53d7\u8fd0\u884c\u65f6\u53d8\u91cf:\\n";\r\n    std::cout << "   int x = 5;\\n";\r\n    std::cout << "   square(x);  // \u7f16\u8bd1\u9519\u8bef!\\n";\r\n    std::cout << "   \u4f46 constexpr int x = 5; square(x); \u662f\u5408\u6cd5\u7684\\n\\n";\r\n\r\n    // \u9677\u96312\uff1aconsteval \u4e0e constexpr \u7684\u9009\u62e9\r\n    std::cout << "2. \u9009\u62e9 consteval \u8fd8\u662f constexpr?\\n";\r\n    std::cout << "   - \u5fc5\u987b\u7f16\u8bd1\u671f\u6c42\u503c \u2192 consteval\\n";\r\n    std::cout << "   - \u7f16\u8bd1\u671f\u548c\u8fd0\u884c\u65f6\u90fd\u53ef\u80fd\u4f7f\u7528 \u2192 constexpr\\n";\r\n    std::cout << "   - \u5b89\u5168\u9a8c\u8bc1\uff08\u5982\u8303\u56f4\u68c0\u67e5\uff09 \u2192 consteval\uff08\u7f16\u8bd1\u671f\u5c31\u80fd\u53d1\u73b0\u9519\u8bef\uff09\\n\\n";\r\n\r\n    // \u9677\u96313\uff1aconsteval \u51fd\u6570\u4e0d\u80fd\u83b7\u53d6\u5730\u5740\r\n    std::cout << "3. consteval \u51fd\u6570\u4e0d\u80fd\u83b7\u53d6\u5730\u5740\uff08\u4e0d\u80fd\u4f5c\u4e3a\u51fd\u6570\u6307\u9488\uff09:\\n";\r\n    std::cout << "   consteval int f(int n) { return n; }\\n";\r\n    std::cout << "   auto ptr = &f;  // \u7f16\u8bd1\u9519\u8bef!\\n\\n";\r\n\r\n    // \u9677\u96314\uff1aconsteval \u51fd\u6570\u4e2d\u7684\u9650\u5236\r\n    std::cout << "4. consteval \u51fd\u6570\u7684\u9650\u5236\u4e0e constexpr \u7c7b\u4f3c:\\n";\r\n    std::cout << "   - \u4e0d\u80fd\u6709 asm \u8bed\u53e5\\n";\r\n    std::cout << "   - \u4e0d\u80fd\u6709 goto\\n";\r\n    std::cout << "   - \u4e0d\u80fd\u6709 static/thread_local \u53d8\u91cf\\n";\r\n    std::cout << "   - \u4f46 C++20 \u653e\u5bbd\u4e86\u5f88\u591a\uff0c\u5141\u8bb8 try-catch\u3001\u865a\u51fd\u6570\u7b49\\n\\n";\r\n\r\n    // \u6f14\u793a\uff1aconsteval \u4e0e static_assert \u914d\u5408\r\n    std::cout << "5. consteval + static_assert \u662f\u7f16\u8bd1\u671f\u9a8c\u8bc1\u7684\u5229\u5668:\\n";\r\n    constexpr auto result = factorial(12);\r\n    static_assert(result == 479001600, "12! \u5e94\u8be5\u7b49\u4e8e 479001600");\r\n    std::cout << "   static_assert(factorial(12) == 479001600) \u901a\u8fc7!\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== consteval \u7acb\u5373\u51fd\u6570 - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:(0,s.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/language/consteval",children:"cppreference: consteval \u7acb\u5373\u51fd\u6570"})}),"\n"]})]})}function d(n={}){const{wrapper:t}={...(0,o.R)(),...n.components};return t?(0,s.jsx)(t,{...n,children:(0,s.jsx)(u,{...n})}):u(n)}},28453(n,t,r){r.d(t,{R:()=>c,x:()=>a});var e=r(96540);const s={},o=e.createContext(s);function c(n){const t=e.useContext(o);return e.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function a(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:c(n.components),e.createElement(o.Provider,{value:t},n.children)}}}]);